// ERROR HANDLER: Captura msgs que falharam no Salvar Interação
// Prepara payload para INSERT na wa_dead_letter_queue
const items = $input.all();
const results = [];

for (const item of items) {
  const error = item.json;

  let rawPayload;
  try {
    rawPayload = $('Normalizar Webhook').first().json;
  } catch (e) {
    rawPayload = error;
  }

  results.push({
    json: {
      message_id: rawPayload.message_id || null,
      raw_payload: JSON.stringify(rawPayload),
      error_message: (error.message || error.error || JSON.stringify(error)).substring(0, 500),
      error_node: 'Salvar Interação',
      pipeline_stage: 'save',
      retry_count: 0,
      status: 'pending'
    }
  });
}

return results;
